type LoadingState = 'idle' | 'loading' | 'success' | 'error';
type FetchState<T> = { status: LoadingState; data: T | null; error: Error | null };
type FetchAction<T> =
  | { type: 'FETCH_START' }
  | { type: 'FETCH_SUCCESS'; payload: T }
  | { type: 'FETCH_ERROR'; error: Error };

function useFetch<T>(url: string): FetchState<T> {
  const [state, dispatch] = useReducer(
    (s: FetchState<T>, a: FetchAction<T>): FetchState<T> => {
      switch (a.type) {
        case 'FETCH_START': return { ...s, status: 'loading' };
        case 'FETCH_SUCCESS': return { status: 'success', data: a.payload, error: null };
        case 'FETCH_ERROR': return { status: 'error', data: null, error: a.error };
        default: return s;
      }
    },
    { status: 'idle', data: null, error: null }
  );

  useEffect(() => {
    dispatch({ type: 'FETCH_START' });
    fetch(url)
      .then(r => r.json() as Promise<T>)
      .then(data => dispatch({ type: 'FETCH_SUCCESS', payload: data }))
      .catch(error => dispatch({ type: 'FETCH_ERROR', error }));
  }, [url]);

  return state;
}
